def p(g):
    N = len(g)
    s = N - 3
    # find cyan row and column
    r_c = next(i for i, r in enumerate(g) if len(set(r)) == 1)
    cyan = g[r_c][0]
    c_c = next(j for j in range(N) if all(g[i][j] == cyan for i in range(N)))
    # positions of 2x2 block and green region
    if r_c == 2:
        r2, r_g = 0, 3
    else:
        r2, r_g = N - 2, 0
    if c_c == 2:
        c2, c_g = 0, 3
    else:
        c2, c_g = N - 2, 0
    tl = g[r2][c2]
    tr = g[r2][c2+1]
    bl = g[r2+1][c2]
    br = g[r2+1][c2+1]
    # find green color
    green = next(g[r][c] for r in range(r_g, r_g + s) for c in range(c_g, c_g + s) if g[r][c] not in (0, cyan))
    o = [[0]*s for _ in range(s)]
    h = s // 2
    for r in range(r_g, r_g + s):
        for c in range(c_g, c_g + s):
            if g[r][c] == green:
                dr, dc = r - r_g, c - c_g
                if dr < h:
                    o[dr][dc] = tl if dc < h else tr
                else:
                    o[dr][dc] = bl if dc < h else br
    return o

